#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int linearSearch(const vector<int>& arr, int target)
{
    for (int i = 0; i < arr.size(); i++)
    {
        if (arr[i] == target)
        {
            return i;
        }
    }
    return -1;
}

int binarySearch(const vector<int>& arr, int target)
{
    int left = 0;
    int right = arr.size() - 1;

    while (left <= right)
    {
        int mid = (left + right) / 2;

        if (arr[mid] == target)
        {
            return mid;
        }
        else if (arr[mid] < target)
        {
            left = mid + 1;
        }
        else
        {
            right = mid - 1;
        }
    }
    return -1;
}

int main()
{
    vector<int> numbers = {4, 12, 7, 23, 9, 1, 18};
    int target = 23;

    int linearResult = linearSearch(numbers, target);
    cout << "Dogrusal arama: " << target << " indeks " << linearResult << "'de bulundu" << endl;

    // Binary arama icin dizi siralanmali
    vector<int> sortedNumbers = numbers;
    sort(sortedNumbers.begin(), sortedNumbers.end());

    int binaryResult = binarySearch(sortedNumbers, target);
    cout << "Binary arama: " << target << " indeks " << binaryResult << "'de bulundu" << endl;

    int notFound = linearSearch(numbers, 99);
    cout << "\n99 araniyor (bulunamayacak): " << notFound << endl;

    return 0;
}
